import { Component, Prop, h, Element, EventEmitter, Event, State, Listen } from '@stencil/core';

import { KEYBOARD_KEYS } from '../../models/keycodes.model';
import { generateRandId } from '../../utils/utils';

import { IconButtonSize, IconButtonType, IconButtonVariants } from './wdpr-icon-button.model';
import { getButtonClass, notificationPaddingClasses, getNotificationSizeClass } from './wdpr-icon-button.utils';
import { NotificationTypes } from '../wdpr-notification/wdpr-notification.model';

@Component({
  tag: 'wdpr-icon-button',
  shadow: true,
})
export class WdprIconButton {
  /**
   * Reference to host element
   * @type {HTMLWdprIconButtonElement}
   */
  @Element() el: HTMLWdprIconButtonElement;

  /**
   * The internal ID for the component. It is used internally and is not exposed.
   */
  @State() private _internalId: string;

  @Prop({ reflect: true, mutable: true }) showNotificationBadge: boolean = false;

  @Prop() buttonId?: string;
  @Prop() customTabIndex?: number = 0;

  @Prop() type: IconButtonType = 'button';
  @Prop() size: IconButtonSize = 'medium';
  @Prop() variant: IconButtonVariants = 'primary';

  @Prop() iconName: string;
  @Prop() disabled = false;
  @Prop({ attribute: 'a11y-expanded' }) a11yExpanded?: 'true' | 'false';
  @Prop() notificationNumber: number = 0;
  @Prop() notificationType: NotificationTypes = 'alert';

  @Prop({ attribute: 'a11y-label' }) a11yLabel!: string;

  @Event({ eventName: 'clicked' }) clicked: EventEmitter<boolean>;

  componentWillLoad() {
    this._internalId = this.buttonId || `wdpr-icon-button-${generateRandId()}`;
  }

  private onClick = () => {
    this.clicked.emit(true);
  };

  @Listen('keydown')
  handleKeyDown(ev: KeyboardEvent) {
    if (ev.key == KEYBOARD_KEYS.ESCAPE) {
      ev.preventDefault();
      (document.activeElement as HTMLElement)?.blur();
    }
  }

  private get _notificationSize() {
    return getNotificationSizeClass(this.variant, this.size);
  }

  private get _buttonClass() {
    return getButtonClass(this.variant, this.size);
  }

  private get _notificationPositionClass() {
    const variant = this.variant === 'bgPrimary' || this.variant === 'bgSecondary' ? 'with-bg' : 'without-bg';

    return notificationPaddingClasses[variant][this.size];
  }

  private get _accessibleLabel() {
    if (this.showNotificationBadge && this.notificationNumber > 0) {
      const notificationText = this.notificationNumber === 1 ? 'notification' : 'notifications';

      return `${this.a11yLabel}, ${this.notificationNumber} ${notificationText}`;
    }

    return this.a11yLabel;
  }

  render() {
    return (
      <div class="flex items-center justify-center">
        <button
          id={this._internalId}
          type={this.type}
          disabled={this.disabled}
          class={this._buttonClass}
          onClick={this.onClick}
          aria-label={this._accessibleLabel}
          aria-expanded={this.a11yExpanded}
          tabIndex={this.customTabIndex}
          part="button"
        >
          <wdpr-icon-library icon={this.iconName} size={this.size} decorative />

          {this.showNotificationBadge && (
            <span class={`absolute ${this._notificationPositionClass}`}>
              <wdpr-notification-indicator number={this.notificationNumber} size={this._notificationSize} type={this.notificationType} decorative />
            </span>
          )}
        </button>
      </div>
    );
  }
}
